"""
ir_decode.py — DEV TOOL, runs on PC only: python ir_decode.py
Decodes raw Daikin IR captures into human-readable byte fields.
"""

def decode(raw, label=""):
    # Preamble ends at the first gap > 10000 µs
    split = 0
    for i in range(1, len(raw)):
        if raw[i] > 10000:
            split = i + 1
            break

    data = raw[split:]

    # Skip header mark+space (first 2 values)
    data = data[2:]

    # Each bit: (mark, space) pair — space > 800 µs = 1
    bits = []
    for i in range(0, len(data) - 1, 2):
        bits.append(1 if data[i + 1] > 800 else 0)

    # Group into bytes, LSB first
    bytes_out = []
    for i in range(0, len(bits), 8):
        chunk = bits[i:i + 8]
        if len(chunk) == 8:
            val = sum(b << j for j, b in enumerate(chunk))
            bytes_out.append(val)

    # Verify checksum
    if len(bytes_out) >= 19:
        calc = sum(bytes_out[:18]) & 0xFF
        ok = "✓" if calc == bytes_out[18] else f"✗ (expected 0x{calc:02X})"
    else:
        ok = "?"

    print(f"\n{'='*50}")
    print(f"  {label}  ({len(bytes_out)} bytes, checksum {ok})")
    print(f"{'='*50}")
    print(f"  hex: {' '.join(f'{b:02X}' for b in bytes_out)}")
    print()

    if len(bytes_out) < 19:
        print("  Not enough bytes to decode.")
        return bytes_out

    # ---- Decode each meaningful byte ----
    b = bytes_out

    # Byte 5: mode (upper nibble) + power (bit 0)
    mode_map = {0: 'auto', 2: 'dry', 3: 'cool', 4: 'heat', 6: 'fan'}
    mode_nibble = (b[5] & 0xF0) >> 4
    mode = mode_map.get(mode_nibble, f'unknown(0x{mode_nibble:X})')
    power = bool(b[5] & 0x01)
    print(f"  [5]  0x{b[5]:02X}  mode={mode}  power={'ON' if power else 'OFF'}")

    # Byte 6: temperature — F - 28 (Fahrenheit remote mode)
    temp_f = b[6] + 28
    temp_c = (temp_f - 32) / 1.8
    print(f"  [6]  0x{b[6]:02X}  temp={temp_f}°F  ({temp_c:.1f}°C)")

    # Byte 8: fan speed (upper nibble)
    fan_nibble = (b[8] & 0xF0) >> 4
    fan_map = {0xA: 'auto', 0xB: 'quiet', 0x3: 'low', 0x4: 'mid', 0x5: 'high', 0x7: 'turbo'}
    fan = fan_map.get(fan_nibble, f'unknown(0x{fan_nibble:X})')
    print(f"  [8]  0x{b[8]:02X}  fan={fan}")

    # Byte 16: 0x40 when power off
    print(f"  [16] 0x{b[16]:02X}  {'(power-off flag)' if b[16] == 0x40 else ''}")
    print(f"  [18] 0x{b[18]:02X}  checksum {ok}")

    return bytes_out


